mapper.select:
select distinct sds.out_en_name as outTableNameEn, sds.out_cn_name as outTableNameCh, sds.out_protocol as outProtocol, case when ciad.sjzzsjfl is null or ciad.sjzzsjfl = '' then '其他' else ciad.sjzzsjfl end as sjzzsjfl from ( select * from shptstatistics.sjgc_data_summary where CREATE_TIME >= DATE_SUB(date(NOW()), INTERVAL 30 DAY) and out_en_name is not null
and ( upper(out_en_name) like upper(concat('%', concat(#{searchName,jdbcType=VARCHAR}, '%'))) or upper(out_cn_name) like upper(concat('%', concat(#{searchName,jdbcType=VARCHAR}, '%'))) or upper(out_protocol) like upper(concat('%', concat(#{searchName,jdbcType=VARCHAR}, '%'))) )
) sds left join ( select SECONDARYORGANIZATIONCH as sjzzsjfl, sjxjbm from CLASSIFY_INTERFACE_ALL_DATE where objectstate = 1 and PRIMARYORGANIZATIONCH = '原始库' ) ciad on sds.out_protocol = ciad.sjxjbm
